public static ETGPurchPackingSlipControllerExtension construct()
{
    return new ETGPurchPackingSlipControllerExtension();
}

public static void main(Args _args)
{
    SrsReportRunController formLetterController = ETGPurchPackingSlipControllerExtension::construct();
    ETGPurchPackingSlipControllerExtension controller = formLetterController;
    controller.parmReportName(ssrsReportStr(ETGPurchPackingSlip, ETGTradingReport));
    controller.parmArgs(_args);
    controller.startOperation();
}
